meal_type": null, "region_id": null, "address_en": null, "country_id": "korea", "created_at": "2026-04-06T23:24:26.06363+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "濟州龍頭岩，狀似龍頭的火山岩，是濟州市區著名的地標。傳說這是龍想升天卻被天神射下，化為石頭，頭仍朝向天空。高10公尺，矗立在海邊，海浪拍打岩石。傍晚時分，夕陽將龍頭岩染成金黃，是拍攝夕陽最美的角度。周邊有步道、觀景台、咖啡廳。這是濟州市區必訪免費景點，也是認識濟州火山地質的好地方。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "KR", "cuisine_type": null, "dining_style": null, "english_name": "Yongduam Rock", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "0b3329da-828b-4dbf-bf1c-a7ab8833b990", "fax": null, "name": "三清洞", "notes": "藝廊與咖啡館林立的文青街區，韓屋改建店舖散發復古時尚氣息。", "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "seoul", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 37.5833, "chef_name": null, "is_active": true, "longitude