_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "2648c7cd-0e78-41b3-8347-fd7450fa8a77", "fax": null, "name": "Ginger Farm Kitchen", "notes": "推薦有機蔬菜沙拉、泰北香料烤雞。位於One Nimman商場內。人均約300-500泰銖。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/507a40f1-5b10-452b-a991-731eae45ea7f-1.jpeg"], "rating": null, "address": null, "city_id": "chiang-mai", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 18.7883, "chef_name": null, "is_active": true, "longitude": 98.9653, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:23:02.595716+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Ginger Farm Kitchen》位於清邁郊區的有機農場，四周是稻田與香草園。餐廳的食材直接從農場採摘，菜單隨季節更動。泰式香料雞的香茅來自門外的香草園、青木瓜沙拉的木瓜是早上現摘、椰奶咖哩的椰子是隔壁椰林的。用餐空間是開放式木造平台，四面無牆,微風穿堂而過,稻田與遠山構成天然背景。這裡的料理不追求精緻擺盤，而是專注於食材本身的新鮮度。午後來此用餐，點杯泰式奶茶,看著農夫在田間工作,時間會自然放慢。這是清邁式的慢食哲學——從土地到餐桌,一切誠實可見。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Ginger Farm Kitchen", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_gro