ite": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": null, "chef_name": null, "is_active": true, "longitude": null, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:24:08.092502+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《沙美島火舞餐廳》每晚在沙灘上演出驚險刺激的火舞秀,表演者揮舞火把、火棒,配合音樂節奏展現高難度特技。餐廳供應泰式海鮮BBQ與西式料理,座位區直面海灘。夜幕低垂、火光搖曳、海浪拍岸,營造原始而浪漫的氛圍。是沙美島夜生活的亮點,適合情侶與追求特殊體驗的旅客。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Fire Show Koh Samet", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "39da392b-c88c-4412-80da-9b19213f6ca4", "fax": null, "name": "梨泰院", "notes": "異國風情購物區，各國美食餐廳與酒吧聚集，夜生活精彩。", "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "seoul", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 37.5344, "chef_name": null, "is_active": true, "longitude": 126.9944, "meal_type": null, "region_id": null, "address_en": null, "country_id": "korea", "created_at": "2026-04-06T23:23:25.022139+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "首爾梨泰院，多元文化街區。清真寺、異國餐廳、夜店、酒吧密集。這裡是首爾最國際化的地方，也是LGBT友善社區。韓劇《梨泰院Class》讓這裡更紅。白天逛特色商店、吃異國料理，夜晚酒吧街熱鬧。這是體驗首爾多元文化的窗口。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "KR", "cuisine_type": null, "dining_style": null, "english_name": "Itaewon", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "3a178ed2-7ffa-4276-acca-b0f7c3a2ed93", "fax": null, "name": "Huen Muan Jai", "notes": "必點Khao Soi（咖哩麵）、炸豬皮、青辣椒醬。座位有限建議早到。人均約200-400泰銖。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/55df99eb-1330-4b9e-a9ba-001d455c3511-1.jpeg"], "rating": null, "address": null, "city_id": "chiang-mai", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 18.7867, "chef_name": null, "is_active": true, "longitude": 98.9892, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:43.97962+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Huen Muan Jai》藏在清邁古城內的木造老宅，保留了蘭納建築的高腳結構與柚木雕花。這裡的泰北料理不追求創新，而是忠實呈現傳統味型。Sai Ua 香腸的香料比例、Khao Soi 的椰奶濃度、Nam Prik 辣椒醬的發酵程度，都是祖母輩傳下來的配方。用餐空間不大，木桌木椅散發出老木頭特有的氣味，午後陽光從木窗縫隙灑進來。這裡不接受訂位，來晚了就要等。但等待是值得的——這是清邁少數還保有家的感覺的餐廳。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Huen Muan Jai", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "3b32a88b-e1d8-4834-9e94-80953fb47c50", "fax": null, "name": "Gaggan Anand", "notes": "亞洲50最佳餐廳常客，印度創意料理。無菜單體驗約25道菜，每道都是味覺與視覺的驚喜。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/61ce8f71-bd00-425c-8c4e-30029775a40c-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7367, "chef_name": null, "is_active": true, "longitude": 100.5456, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:44.37176+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Gaggan Anand》印度裔主廚 Gaggan Anand 將分子料理技術用在印度風味上,創造出 25 道菜的感官實驗。菜單沒有文字,只有 emoji,你得用味覺去解讀每道菜的敘事。液態氮製成的優格球在口中爆裂,咖哩葉泡沫帶著香料的記憶,tandoori 羊排的煙燻味與甜菜根泥的土壤感形成對話。這不是傳統印度菜,而是印度味覺記憶的解構與重組。Gaggan 在餐廳裡放 rock 音樂,鼓勵客人拍照,打破 fine dining 的嚴肅性。這是曼谷最叛逆的餐桌。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Gaggan Anand", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "3c056cda-a184-478f-8237-983d0efaa59d", "fax": null, "name": "Le Du", "notes": "曼谷一星米其林，現代泰式料理。主廚將泰國食材以當代技法呈現，菜單隨季節更換。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/37bf642a-67e9-48c7-9c7b-2c4ef5079fff-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7242, "chef_name": null, "is_active": true, "longitude": 100.5283, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:34.081203+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Le Du》位於 Silom 區,主廚 Ton 以當代技法演繹泰國在地食材。菜單隨季節更動,可能出現以泰北香料醃製的海鱸、搭配發酵辣椒的伊比利豬,或是用椰糖提味的甜點。擺盤精緻但不過度裝飾,專注於味道本身的層次。侍酒師能精準搭配葡萄酒與每道菜,也提供泰國本土蒸餾酒的選項。空間以深色木質與水泥為基調,低調而沉穩。這裡證明了泰國料理可以超越街頭小吃的框架,在米其林標準下仍保有自己的文化主體性。價格不低,但物有所值。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Le Du", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "3c875089-05c5-4d99-a8fb-1205e2fd9d07", "fax": null, "name": "邦拉夜市", "notes": "芭東最熱鬧的夜生活區。有酒吧、夜店、按摩店。體驗普吉島夜生活的地方。", "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "phuket", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 7.8961, "chef_name": null, "is_active": true, "longitude": 98.3028, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:23:36.114503+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "普吉芭東海灘最熱鬧的夜市和夜生活區，酒吧、餐廳和購物攤位林立。入夜後燈火通明，是普吉島派對的中心地帶。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Bangla Road", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_co