 "english_name": "LeTAO", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "3fb3abc0-0a9c-4fbc-90ad-7bc895708682", "fax": null, "name": "十號胡同", "notes": "吉隆坡的美食天堂，集合馬來西亞各地名店。在冷氣舒適的環境中品嚐各種在地美食，是雨天或怕熱遊客的好選擇。", "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "kuala-lumpur", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 3.1469293, "chef_name": null, "is_active": true, "longitude": 101.7118546, "meal_type": null, "region_id": null, "address_en": null, "country_id": "malaysia", "created_at": "2026-04-06T23:22:47.479939+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "吉隆坡十號胡同，PavilionKL購物中心地下美食街，集結16家馬來西亞老字號美食。何榮記雲吞麵、金蓮記福建炒麵、新峰肉骨茶都在這裡。冷氣開放、環境乾淨，比夜市舒適。這是品嚐馬來西亞經典美食的一站式好地方，也是雨天備案首選。價格約10-20馬幣/份。建議午餐或晚餐前往。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "MY", "cu