 null, "english_name": null, "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "42d2c390-ee1b-450b-88e5-0edc9ca732b9", "fax": null, "name": "髒鴨飯", "notes": "峇里島名菜Bebek Bengil，將鴨子用多種香料醃製後油炸。外皮酥脆，肉質軟嫩。Bebek Bengil是最著名的店家，環境是稻田美景。\n\n旅遊提示：午餐去最好，可以看稻田風景", "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "bali", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": -8.2271303, "chef_name": null, "is_active": true, "longitude": 115.1919203, "meal_type": null, "region_id": null, "address_en": null, "country_id": "indonesia", "created_at": "2026-04-06T23:24:31.223518+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "烏布髒鴨飯，烏布最有名的髒鴨餐廳。鴨肉炸得酥脆、肉質軟嫩，配上白飯、蔬菜、sambal辣醬，香辣過癮。餐廳環境優雅，稻田景觀、發呆亭、荷花池。需提前訂位。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "ID", "cuisine_type": null, "di