pe": null, "dining_style": null, "english_name": null, "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "4efb28cc-131d-48e8-a2f7-bd00f6cf60fb", "fax": null, "name": "Here Hai", "notes": null, "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/c9394bf5-4609-4fe2-8ea9-630349425a97-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/c9394bf5-4609-4fe2-8ea9-630349425a97-2.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7301697, "chef_name": null, "is_active": true, "longitude": 100.5863296, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:09:59.760376+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Here Hai》「Hai」在泰文裡是「找到了」的意思,這間海鮮餐廳的名字帶著一點尋寶的意味。主廚 Ton 曾在日本料理餐廳工作多年,將日式處理海鮮的細膩手法融入泰式調味。生蠔佐青檸與魚露,刺身級的紅魽魚配泰式香料油,烤大蝦淋上椰糖與羅望子醬。海鮮的鮮度是基礎,調味是昇華。餐廳位於 Thonglor 區的巷弄深處,沒有招牌,需要熟人帶路或 Google Maps 精準導航。這種隱藏感不是做作,而是曼谷在地人才懂的生活美學:好東西不需要宣傳。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Here Hai", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "4f8584aa-fd89-4652-a26d-3b8ba8afa7d2", "fax": null, "name": "七輪燒肉", "notes": "", "phone": "", "awards": null, "images": null, "rating": null, "address": "", "city_id": "naha", "ratings": null, "website": "", "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 26.215, "chef_name": null, "is_active": true, "longitude": 127.68, "meal_type": null, "region_id": "jp_okinawa", "address_en": null, "country_id": "japan", "created_at": "2026-04-06T23:23:17.099203+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "沖繩極具人氣的高 CP 值燒肉選擇。店內堅持使用傳統炭火七輪烤爐，鎖住肉質原汁原味。從鮮美牛五花到豐富的海鮮食材一應俱全，搭配平實的價格與熱鬧的用餐氣氛，深受在地人與遊客喜愛。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "JP", "cuisine_type": null, "dining_style": null, "english_name": "Shichirin Yakiniku", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "509a4855-df21-43d1-9c2e-e5a4e215965f", "fax": null, "name": "Ristr8to Coffee", "notes": "必點招牌拉花咖啡，可欣賞精緻的咖啡藝術。位於尼曼區。咖啡約80-150泰銖。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/377898dd-ecea-4016-b8b7-47d4367cb365-1.jpeg"], "rating": null, "address": null, "city_id": "chiang-mai", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 18.7925, "chef_name": null, "is_active": true, "longitude": 98.9658, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:23:02.086222+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Ristr8to Coffee》老闆 Arnon 是泰國拉花冠軍，店內牆上掛滿獎牌與證書。這裡的咖啡豆來自泰北山區，從採收、烘焙到萃取都有嚴格標準。單品咖啡會標註產區、處理法、烘焙度，像品酒一樣專業。但 Arnon 不是那種嚴肅到讓人緊張的職人，他會用英文解釋每支豆子的風味差異，也歡迎你只點杯拿鐵。店內空間不大，木質吧台、手沖器具、烘豆機，一切專注於咖啡本身。這是清邁精品咖啡文化的起點之一——不追求網美風格，只追求一杯好咖啡。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Ristr8to Coffee", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "50b64704-11e3-45a5-b01a-ff6430ddc39d", "fax": null, "name": "沖繩美食居酒屋", "notes": "品嚐沖繩獨特料理的在地居酒屋，海葡萄、苦瓜炒蛋和泡盛酒是必點。熱情的店主和三線琴伴奏是沖繩夜晚的特色。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/9e2bf21d-482b-4a56-b5c7-f0bbdd11eeb6-1.jpeg"], "rating": null, "address": null, "city_id": "naha", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 26.2147, "chef_name": null, "is_active": true, "longitude": 127.6775, "meal_type": null,