"country_id": "vietnam", "created_at": "2026-04-06T23:22:42.666033+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "會安料理教室，體驗越南料理製作的烹飪課程。通常包含市場導覽、料理教學、用餐品嚐。專業主廚示範，學員動手做，英文教學。完成後可以帶走食譜。這是認識越南飲食文化最深入的方式，也是會安熱門體驗活動。課程約3-4小時，需提前預約。多家料理教室可選。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "VN", "cuisine_type": null, "dining_style": null, "english_name": "Hoi An Cooking Class", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "540ffb78-a009-4aac-8a13-7c9fb3253468", "fax": null, "name": "王子戲院豬肉粥", "notes": "必點豬肉粥配油條和溫泉蛋。位於唐人街附近。人均約60-100泰銖。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/89a94573-3a90-4e0a-9f00-76890422a256-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7533, "chef_name": null, "is_active": true, "longitude": 100.5014, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:40.806257+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《王子戲院豬肉粥》位於唐人街邊緣,店面小到容易錯過。粥底以碎米熬煮至綿密,加入豬肉末、皮蛋與薑絲,撒上油條碎增加口感層次。這碗粥的精髓在於比例——粥不能太稠也不能太稀,肉末要有顆粒感但不能柴。凌晨一點到早上九點營業,吸引夜歸人與早起工人。塑膠椅、金屬桌、昏黃燈光,典型的街頭食堂配置。沒有英文菜單,老闆不會說觀光客語言,但手指菜單就能點餐。這碗粥代表的是華人移民在曼谷扎根的味道記憶,簡單但精準,是深夜或清晨最溫柔的慰藉。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Joke Prince", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "541fddff-f09c-4279-bd75-0c974a7fc4e7", "fax": null, "name": "小琉球海鮮餐廳", "notes": null, "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "c9e386df-3111-4bc6-9ed0-3c