ourmand": false, "chef_profile": null, "country_code": "JP", "cuisine_type": null, "dining_style": null, "english_name": "Azabu Kadowaki", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "6d72c6b2-e1d4-41b4-8977-d6d60d136916", "fax": null, "name": "L'Effervescence", "notes": "生江史伸主廚的法式創意料理，米其林二星，蔬菜料理令人驚艷。", "phone": null, "awards": null, "images": ["https://images.pexels.com/photos/35888/amazing-beautiful-breathtaking-clouds.jpg?auto=compress&cs=tinysrgb&h=650&w=940"], "rating": null, "address": null, "city_id": "tokyo", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 35.6643, "chef_name": null, "is_active": true, "longitude": 139.7262, "meal_type": null, "region_id": "jp_kanto", "address_en": null, "country_id": "japan", "created_at": "2026-04-06T23:24:02.281585+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "東京米其林二星法式餐廳L'Effervescence，位於西麻布。主廚生江史伸強調Satoyama理念，使用日本山野食材，野菜、山菜、自然酒。無菜單品嚐套餐，每道菜呈現日本四季。開放式廚房、輕鬆氛圍。需提前預約。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "JP", "cuisine_type": null, "dining_style": null, "english_name": "L'Effervescence", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "6d8aead8-7004-4c43-ab64-2cd153371c2e", "fax": null, "name": "一蘭拉麵總本店", "notes": null, "phone": null, "awards": null, "images": ["https://images.pexels.com/photos/34024483/pexels-photo-34024483.jpeg?auto=compress&cs=tinysrgb&h=650&w=940"], "rating": null, "address": null, "city_id": "fukuoka", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 33.5886, "chef_name": null, "is_active": true, "longitude": 130.3979, "meal_type": null, "region_id": "jp_kyushu", "address_en": null, "country_id": "japan", "created_at": "2026-04-06T23:23:18.642775+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "一蘭拉麵，博多豚骨拉麵連鎖店，以味集中座位聞名。一人一格、擋板隔開，專注品嚐拉麵。湯頭濃郁、麵條細直、秘傳紅醬辣椒醬是特色。24小時營業分店多，隨時都能吃。這是福岡拉麵代表，也是日本必吃美食。一碗約1,000-1,總本店在博多，朝聖價值高。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "JP", "cuisine_type": null, "dining_style": null, "english_name": "Ichiran Ramen Headquarters", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "6ed00335-fbac-49ae-9db2-15ecebe29198", "fax": null, "name": "LeTAO 本店", "notes": "雙層起司蛋糕是小樽必買伴手禮。現吃和冷凍的口感不同，都很棒。\n[IMAGE_POSITIONS:{\"https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/workspace-files/attractions/1767160631902_o6oc6z.png\":\"center\"}]", "phone": "", "awards": null, "images": null, "rating": null, "address": "", "city_id": "otaru", "ratings": null, "website": "", "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 43.19, "chef_name": null, "is_active": true, "longitude": 141.0028, "meal_type": null, "region_id": "jp_hokkaido", "address_en": null, "country_id": "japan", "created_at": "2026-04-06T23:22:56.614269+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_s