26+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《747 Café》把一架退役的波音 747 改造成咖啡館，停在清邁郊區的稻田中央。機艙內保留了原始座椅與行李架，窗外是連綿的綠色稻田與遠山。這裡的咖啡普通，甜點也不驚豔，但坐在三萬英呎該有的位置上喝咖啡，本身就是一種超現實體驗。午後陽光透過橢圓窗灑進來，你會忘記這是陸地。適合帶孩子來，他們可以在駕駛艙拍照。週末人潮擁擠，平日下午來最舒適。這是清邁式的創意——不追求完美，但絕對有趣。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "747 Café", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "790e9bb7-0a05-4ef2-ad13-33ccb4e71c3c", "fax": null, "name": "鰻魚料理", "notes": null, "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/8dbdf1cb-327b-45fc-a5ba-33ba9f267c69-1.jpeg"], "rating": null, "address": null, "city_id": "yanagawa", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 33.1633, "chef_name": nu