。每週日下午四點開始封街,Ratchadamnoen路變成巨型市集。攤位販售手工藝品、繪畫、銀飾、木雕、棉麻服飾,品質參差但總能找到寶。街頭藝人、傳統舞蹈表演、按摩攤位穿插其間,氛圍熱鬧但不失秩序。在地小吃攤密集,從北方香腸到芒果糯米飯應有盡有。建議傍晚六點前往,先吃晚餐再慢慢逛。人潮擁擠但節奏從容,這是清邁最具代表性的週末儀式——商業、文化、社交在此交織。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Sunday Walking Street", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "8dda32b2-baed-451d-aa9c-1b8af02ab00c", "fax": null, "name": "拉差達火車夜市", "notes": null, "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/aa1c056e-d921-4bb7-8301-aaea166b6b80-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/aa1c056e-d921-4bb7-8301-aaea166b6b80-2.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7524938, "chef_name": null, "is_active": true, "longitude": 100.4935089, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:09:53.613256+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《拉差達火車夜市》最迷人的視角不在地面，而在隔壁購物中心四樓停車場的俯瞰點。從高處望下去，數百頂彩色帆布帳篷排列成工整的方格陣列，藍、橙、綠、紅交織出像素化的城市肌理，夜燈初上時宛如電子螢幕的色塊亮起。這座夜市建於廢棄鐵道舊址，保留了火車車廂作為餐廳包廂，攤位販售的商品從復古球鞋到手作銀飾應有盡有，但真正的主角是那些坐在塑膠椅上大口吃烤肉串、喝泰奶的年輕人——他們讓這個2015年才開張的夜市迅速成為曼谷新世代的社交場域。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Train Night Market Ratchada", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "8e4d0854-da73-4b3e-9c84-a55911d64110", "fax": null, "name": "Jay Fai 痣姐熱炒", "notes": "曼谷傳奇街頭小吃，米其林一星。70歲阿嬤戴護目鏡用炭火烹飪，招牌蟹肉蛋捲需排隊數小時。 | 米其林一星", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/df4cbf79-0d72-415b-99e1-c5adf7a11a3d-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/df4cbf79-0d72-415b-99e1-c5adf7a11a3d-2.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7556, "chef_name": null, "is_active": true, "longitude": 100.5014, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:09:55.095146+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Jay Fai 痣姐熱炒》七十歲的 Jay Fai 戴著滑雪護目鏡,在攝氏兩百度的炭火前翻炒蟹肉蛋包。米其林一星的榮耀並未改變她的堅持：每道菜親手料理,不假他人。蟹肉蛋包用料奢侈到近乎任性,整隻螃蟹的肉與蛋液融合,外層金黃酥脆,內餡濕潤飽滿。這是老曼谷的手藝與當代美食評價體系的碰撞,也是街頭料理如何在全球化浪潮中保持靈魂的範本。排隊三小時是常態,但那盤蛋包端上桌的瞬間,你會理解時間的價值。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Jay Fai", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "8fa8bc14-2070-4169-80c5-532211fcc74a", "fax": null, "name": "法善寺 夫婦善哉", "notes": "夫婦善哉880日圓。位於法善寺橫丁。情侶來吃很應景。", "phone": "", "awards": null, "images": null, "rating": null, "address": "", "city_id": "osaka", "ratings": null, "website": "", "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 34.6689, "chef_name": null, "is_active": true, "longitude": 135.5053, "meal_type": null, "region_id": "jp_kansai", "address_en": null, "country_id": "japan", "created_at": "2026-04-06T23:22:32.571717+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "大阪道頓堀法善寺橫丁的百年甜品店，招牌「夫婦善哉」是兩碗紅豆湯圓，象徵夫妻圓滿。店內保留昭和時代懷舊氛圍，木造建築古樸溫馨。法善寺供奉水掛不動明王，參拜者潑水祈福，青苔覆蓋佛像形成獨特景觀。是體驗大阪傳統甜品與庶民信仰的必訪老舖，也是情侶約會聖地。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "JP", "cuisine_type": null, "dining_style": null, "english_name": "Meoto Zenzai", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "90189ee4-2d3b-445a-80de-0928f7335bf2", "fax": null, "name": "阿羅娜海灘", "notes": "邦勞島（薄荷島旁）最熱鬧的海灘，是潛水和浮潛的基地。沙灘上有眾多餐廳和酒吧。是薄荷島住宿的熱門區域。\n\n旅遊提示：很多潛店在這裡，可安排考潛水證照", "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "bohol", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 9.5484309, "chef_name": null, "is_active": true, "longitude": 123.7719579, "meal_type": null, "region_id": null, "address_en": null, "country_id": "philippines", "created_at": "2026-04-06T23:22:48.048226+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "薄荷島阿羅娜海灘，薄荷島最熱鬧的海灘，長約1.5公里。白沙灘、清澈海水、餐廳、酒吧、按摩店、潛水店林立。可跳島、浮潛、潛水、看海豚。這是薄荷島必訪景點，也是夜生活中心。住宿約3,000-15,000披索/晚。可搭配巧克力山、眼鏡猴一起遊覽。夜晚有 Fire Dance 表演。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "PH", "cuisine_type": null, "dining_style": null, "english_name": "Alona Beach", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": fals