ar": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "90d8b141-b38c-4df9-9151-fe21ed477ae3", "fax": null, "name": "The Bay 101", "notes": "海雲台最佳夜景拍攝點，以摩天大樓海雲台LCT為背景。有遊艇碼頭、餐廳和酒吧。許多韓劇在此取景。白天可看海，晚上看夜景。\n\n旅遊提示：建議晚餐時段預約靠窗位子", "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "busan", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 35.1614, "chef_name": null, "is_active": true, "longitude": 129.1325, "meal_type": null, "region_id": null, "address_en": null, "country_id": "korea", "created_at": "2026-04-06T23:22:33.00722+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "釜山The Bay 101，海雲台海景複合空間。遊艇碼頭、餐廳、咖啡廳、酒吧集中於此。夜晚燈光倒映海面，營造浪漫氛圍。可以在此用餐、喝咖啡，欣賞海雲台夜景、海雲台LCT、廣安大橋。這是釜山最時尚的海景景點，也是約會聖地。建議傍晚前來，可以看到日落與夜景。週末人潮眾多，餐廳需預約。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "KR", "cuisine_type": null, "dining_style": null, "english_name": "The Bay 101", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "grou