y": null}, {"id": "919b450d-e01d-4f8f-a84d-3d1641cda002", "fax": null, "name": "Tong Tem Toh", "notes": "推薦Nam Prik Ong（肉末番茄醬）配炸豬皮、Laab（涼拌肉）。多間分店。人均約150-300泰銖。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/f724dc53-1c9a-495a-b4e2-fedef82fbc55-1.jpeg"], "rating": null, "address": null, "city_id": "chiang-mai", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 18.7867, "chef_name": null, "is_active": true, "longitude": 98.9931, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:23:17.864425+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Tong Tem Toh》是清邁大學附近的學生食堂，經營超過三十年。這裡沒有英文菜單，老闆不會說觀光客語言，但手指菜單就能點餐。招牌是炸豬皮拌青木瓜沙拉，豬皮酥脆到咬下會發出聲音，青木瓜的酸辣與魚露的鹹鮮平衡得恰到好處。午餐時段擠滿穿制服的大學生，翻桌速度極快。塑膠椅、金屬桌、電風扇呼呼作響，典型的泰國街頭食堂配置。這不是精緻的用餐體驗，而是最真實的清邁日常——便宜、快速、好吃。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Tong Tem Toh", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_