estrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "94eedde7-2617-49ad-a16e-61d0c14d9a39", "fax": null, "name": "Rosewood曼谷", "notes": "曼谷最頂級的奢華酒店之一，位於Phloen Chit商業區。30層樓高的建築設計現代典雅，屋頂酒吧景觀絕佳。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/664e7c73-9822-42b3-9b08-632fba8c94d9-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7433, "chef_name": null, "is_active": true, "longitude": 100.5478, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:58.916017+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Rosewood曼谷》80 層樓的摩天大樓矗立在商業區中心,外觀是曲線流動的玻璃帷幕,內部是 Art Deco 與泰式元素的混搭。頂樓的 Nan Bei 餐廳供應粵菜與川菜,落地窗外是 360 度的城市夜景。酒店的設計細節藏著泰國傳統工藝:手工編織的藤椅、Jim Thompson 絲綢抱枕、柚木屏風。這是一種不著痕跡的在地性,不是刻意的民族風情展示,而是將傳統元素內化為當代語言。泳池位於 30 樓,你可以在半空中游泳,感受高度帶來的失重感。這是曼谷的垂直奢華,也是全球化都市的精緻樣本。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": null, "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lun