in_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "978998f0-3210-4e0b-ad89-9c9b13480f8d", "fax": null, "name": "Bo.Lan", "notes": "曼谷米其林餐廳，堅持永續泰式料理。使用有機農場食材，重現傳統泰國宮廷菜的精緻風味。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/79ee3ec4-92fa-4a83-ae0b-e40d5c93dc75-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7297, "chef_name": null, "is_active": true, "longitude": 100.5853, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:40.032372+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Bo.Lan》曾獲米其林一星,是曼谷永續理念餐廳的先驅。由澳洲主廚Dylan Jones和泰籍妻子Bo Songvisava創立,強調零浪費、在地食材、有機耕作,呈現傳統皇家泰菜的精緻風味。14道菜品嚐套餐,每道菜都有文化故事:古法醃漬的發酵魚、清邁北部的香料咖哩、曼谷宮廷甜點,透過現代技法重新詮釋。餐廳裝潢低調雅致,服務專業細膩,用餐時間約3小時,價格約2,500-3,500泰銖。適合追求深度泰式美食體驗的饕客。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Bo.Lan", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_note