a", "fax": null, "name": "紅大哥海南雞飯", "notes": "與Go-Ang（粉紅）各有支持者，建議都嘗試。人均約60-100泰銖。清晨就開始營業。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/2758d361-49d9-40d1-8096-9c6cc9518cc6-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7453, "chef_name": null, "is_active": true, "longitude": 100.5336, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:23:00.450529+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《紅大哥海南雞飯》位於水門市場巷弄深處，一個讓當地人每天排隊的老字號。廚師從凌晨開始燉煮雞湯，米飯吸飽雞油香氣，配上薑蔥醬與特製辣醬。這裡的雞肉不追求滑嫩到失去口感，而是保留纖維的扎實感，佐以醬料才完整。中午前座位難求，下午三點收攤。牆上泛黃的菜單、磨損的木桌、老闆娘熟練的切雞手法，都是時間累積的證明。不是網紅店，是生活的一部分。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Kuang Heng Pratunam", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "a7772b91-45fc-44af-bdd5-1ba10245bc6b", "fax": null, "name": "河內古街咖啡館", "notes": null, "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "hanoi", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": null, "chef_name": null, "is_active": true, "longitude": null, "meal_type": null, "region_id": null, "address_en": null, "country_id": "vietnam", "created_at": "2026-04-06T23:24:37.262646+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《河內古街咖啡館》Cafe Giang 是蛋咖啡(Egg Coffee)的發源地,創辦人 Nguyen Van Giang 在1940年代因牛奶短缺而發明這種飲品。蛋黃打發後加入煉乳、奶油與咖啡,形成綿密泡沫層,口感像提拉米蘇。咖啡館藏在舊城區巷弄三樓,木製桌椅、老相片、泛黃牆面,保留昔日氛圍。第二代、第三代持續經營,配方從不外傳。這裡不只是咖啡館,而是河內創意與韌性的象徵——物資匱乏時代的發明,至今成為城市名片。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "VN", "cuisine_type": null, "dining_style": null, "english_name": "Cafe Giang (Egg Coffee)", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu