"private_room_capacity": null}, {"id": "ac14c770-35fc-4512-b416-5d222819cda0", "fax": null, "name": "Jay Fai", "notes": "曼谷傳奇街頭小吃，米其林一星。70歲阿嬤戴護目鏡用炭火烹飪，招牌蟹肉蛋捲需排隊數小時。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/7e35c368-0b21-4f38-ac5a-a7b2f2267ec3-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7556, "chef_name": null, "is_active": true, "longitude": 100.5014, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:40.314774+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Jay Fai》是全球第一家獲得米其林一星的街邊大排檔，2017年起連續摘星至今。70多歲的「痣姐」戴著滑雪護目鏡在炭火前獨自掌廚，堅持現點現做。招牌蟹肉蛋捲(Crab Omelette)用料奢華，整隻藍蟹肉包裹在鬆軟蛋皮中，一份1,000泰銖卻依然一位難求。乾炒河粉、海鮮咖哩同樣精彩。用餐需提前數週預約，營業時間隨痣姐心情而定,但只要嚐過那金黃蟹香與炭火氣息，就能理解為何全世界饕客甘願等待。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Jay Fai", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_p