ull, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "b23b72c0-4e2b-4b96-a07e-4b14d09d431c", "fax": null, "name": "王權雲頂大樓Mahanakhon", "notes": "門票約880泰銖。建議傍晚去看日落和夜景。頂樓酒吧有低消。穿裙子的話玻璃地板下會用布遮住。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/a6b58004-a4c0-4fdf-948f-fcb1f7bdb23c-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7238, "chef_name": null, "is_active": true, "longitude": 100.5283, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:23:00.809266+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《王權雲頂大樓 Mahanakhon》以像素化外觀成為曼谷天際線的新標誌。78 樓觀景台設有透明玻璃地板,俯瞰城市肌理——從密集的老城區到新興的高樓群,都市擴張的痕跡清晰可見。日落時段光線變化最豐富,但也是人潮最多的時刻。頂樓酒吧提供調酒與輕食,價格已包含觀景費用,相對划算。這座建築的價值不在於高度本身,而在於提供了一個抽離的視角,讓你重新丈量這座城市的尺度。混亂的街道在 300 公尺高空變成秩序井然的線條,是另一種理解曼谷的方式。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": null, "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_or