59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "bbe356ea-6d00-4344-ba9a-c26d10732d2f", "fax": null, "name": "Thipsamai 泰國第一炒河粉", "notes": null, "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/2faa94dc-d159-48ef-bb98-84a972e9bd1c-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/2faa94dc-d159-48ef-bb98-84a972e9bd1c-2.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7524938, "chef_name": null, "is_active": true, "longitude": 100.4935089, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:09:52.272812+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Thipsamai 泰國第一炒河粉》自封「泰國第一」的名號並非虛言,這間老店從 1966 年開業至今,炒河粉的手藝傳承三代。招牌是蛋包炒河粉,整顆蛋煎成薄如紙的蛋皮,包裹著酸甜適中的河粉,一刀劃開,蛋液與河粉交融。河粉的韌度恰好,蝦子新鮮飽滿,羅望子與棕櫚糖的比例是秘方。店內永遠人滿為患,服務生端著盤子在人群中穿梭,廚房的火光與油煙構成老曼谷的視覺記憶。這是炒河粉的標準答案,也是時間的味道。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Thipsamai", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "bd0d4055-e8ae-4bd3-b8d1-f5663250f69c", "fax": null, "name": "四方水上市場", "notes": "人工打造的水上市場，可搭船遊覽。有表演和餐廳。門票200泰銖。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/035d089a-8d4c-40f5-996b-c7fe4871e221-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.5231, "chef_name": null, "is_active": true, "longitude": 99.9619, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:24:27.541571+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "曼谷水上市場，保留泰國傳統水上交易文化。小船載滿水果、小吃、紀念品，船家划船叫賣。芒果糯米飯、船麵、椰子冰淇淋都可以在船上購買。早上7-9點最熱鬧。距曼谷市區約80公里，需包車或參加旅行團。體驗原汁原味的泰式水上生活。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Pattaya Floating Market", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "bd11b6d7-ac23-42c8-a500-3571c9c69204", "fax": null, "name": "Chocolate Ville", "notes": "位於曼谷郊區，需開車前往。推薦豬肋排、德國豬腳。入場費50泰銖可抵餐費。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/f7a618d8-362d-4ad9-a12d-195ed8ab57b5-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.8833, "chef_name": null, "is_active": true, "longitude": 100.6833, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:43.437041+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Chocolate Ville》位於曼谷近郊,佔地13英畝的歐式鄉村庭園餐廳。風車、小木屋、小橋流水、彩色房屋等夢幻造景,彷彿置身歐洲童話村莊。入夜燈光浪漫,湖面倒影璀璨,是網美打卡和家庭聚餐熱點。餐廳提供泰式、西式、日式料理,份量豐盛,價格親民,人均約300-500泰銖。戶外座位可餵魚、拍照,室內有冷氣適合炎熱天氣。建議傍晚前往,先在園區拍照,再享用晚餐,最後欣賞夜景,安排2-3小時最合適。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Chocolate Ville", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "c01974cd-d560-4dec-bbb8-0b6744ab7eed", "fax": null, "name": "Go-Ang Pratunam 粉紅海南雞飯", "notes": null, "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/944d7b4b-cd84-400a-a795-a6570049db92-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/944d7b4b-cd84-400a-a795-a6570049db92-2.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7496404, "chef_name": null, "is_active": true, "longitude": 100.5420858, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:09:52.72141+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Go-Ang Pratunam 粉紅海南雞飯》店員身穿粉紅色制服,招牌也是粉紅色,這間 24 小時營業的雞飯店是曼谷最具辨識度的深夜食堂。海南雞飯的作法標準:白斬雞、雞油飯、薑蓉醬、清湯,但勝在穩定與快速。點餐到上菜不超過五分鐘,翻桌率極高,永遠有人在排隊也永遠有空位。這裡是計程車司機、夜班工人、醉酒遊客的共同選擇,階級與國籍在這裡失去意義,大家都只是想吃一盤熱騰騰的雞飯。粉紅色的視覺記憶點讓它成為曼谷的打卡地標,但本質上它就是一間便宜、快速、不難吃的連鎖店。這是都市夜生活的基礎設施。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Go-Ang Pratunam", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "c08062a3-1fe3-4bd5-a6cf-0885001ee7ef", "fax": null, "name": "河內夜市", "notes": "還劍湖北邊的週末夜市。有小吃、衣服、紀念品。可體驗道地河內夜生活。", "phone": null,