"awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/64edb5d5-70b3-4011-827b-ee3885cac271-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/64edb5d5-70b3-4011-827b-ee3885cac271-2.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7524938, "chef_name": null, "is_active": true, "longitude": 100.4935089, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:09:53.127124+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《榮泰米粉湯》藏身舊城區巷弄,僅有四張塑膠桌的簡陋店面。老闆堅持用豬骨熬湯六小時,湯頭呈現琥珀色澤,清澈但層次豐富。米粉有三種粗細可選,搭配手工豬肉丸與炸豬皮。調味台上的辣椒醋與魚露由客人自行調配,在地人習慣加入大量白胡椒提味。早上七點開賣,中午十二點售罄收攤,週日公休。牆上貼滿老照片與報導,但老闆從不主動攀談。這碗湯的價值在於純粹——沒有花俏配料,只有對基本味道的專注打磨。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Guay Tiew Mu Rung Rueang", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_pri