mended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "d754d929-d1eb-4af9-8d93-58f466163220", "fax": null, "name": "Savoey", "notes": "推薦咖哩蟹、蒜蓉蝦、冬蔭功。Mercury Ville和Terminal 21都有分店。人均約500-800泰銖。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/fe76aaf4-4cfb-4a02-bbd5-c6b6780eb542-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.745, "chef_name": null, "is_active": true, "longitude": 100.5394, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:45.056662+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Savoey》是曼谷在地人與遊客都愛的連鎖海鮮餐廳，以咖哩螃蟹(Crab Curry)聞名。新鮮螃蟹浸泡在濃郁椰奶咖哩中，黃色醬汁香濃微辣，配上炸饅頭吸附醬汁,一口咬下滿溢的海洋鮮甜。餐廳裝潢走泰式現代風,價格合理,人均約500-1,000泰銖,比高級餐廳親民,但海鮮品質不打折。多家分店分佈曼谷各區,建議提前訂位或避開用餐尖峰,週末晚餐時段往往需等候1小時。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Savoey Seafood", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "d86a0cf6-2930-40af-9a48-812202de200b", "fax": null, "name": "Quintessence", "notes": "東京米其林三星法餐，岸田周三主廚的料理精準細膩，展現法式料理的極致。", "phone": null, "awards": null, "images": ["https://images.pexels.com/photos/18541711/pexels-photo-18541711.jpeg?auto=compress&cs=tinysrgb&h=650&w=940"], "rating": null, "address": null, "city_id": "tokyo", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 35.6581, "chef_name": null, "is_active": true, "longitude": 139.6992, "meal_type": null, "region_id": "jp_kanto", "address_en": null, "country_id": "japan", "created_at": "2026-04-06T23:23:12.00148+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Quintessence》白金台法式餐廳，主廚岸田周三日本首位米其林法餐三星。「素材之本質」哲學，每日產地直送食材低溫烹調、精準火侯，展現食材原味巔峰。吧台開放式廚房近距離觀賞職人技藝，午餐套餐 ¥20,000 起，需提前 1-2 個月預約。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "JP", "cuisine_type": null, "dining_style": null, "english_name": "Quintessence", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "openi