t_season": null, "description": "《Deck 1 Restaurant》河畔的木質平台延伸至湄南河上,你幾乎能觸碰到流動的河水。這間餐廳沒有過度裝飾,保留了河岸倉庫的原始結構,鐵皮屋頂、水泥地板、木製長桌。菜單是泰式家常菜的精緻版本:冬蔭功的酸辣比例恰到好處,咖哩螃蟹的椰奶香氣濃郁但不膩口。對岸是鄭王廟的尖塔,夜晚打上金色燈光,倒影在河面上破碎又完整。這是曼谷少數能讓你放慢速度的地方,河風吹散城市的燥熱,時間變得可以測量。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Deck 1 Restaurant", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "e6cc19cb-f082-439e-b86a-045bf012a640", "fax": null, "name": "Gaggan Anand", "notes": null, "phone": null, "awards": null, "images": null, "rating": null, "address": "68/1 Soi Langsuan, Lumphini, Pathum Wan, Bangkok", "city_id": "bangkok", "ratings": null, "website": "https://www.gaggananand.com", "category": null, "currency": "THB", "latitude": null, "chef_name": "Gaggan Anand", "is_active": true, "longitude": null, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2025-11-01T10:37:01.491847+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star":