.793607+00:00", "updated_by": null, "best_season": null, "description": "讚岐烏龍麵，日本知名景點，值得造訪體驗。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "JP", "cuisine_type": null, "dining_style": null, "english_name": "Sanuki Udon", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "ea336d63-a662-46a8-b8f8-da94089687d6", "fax": null, "name": "大屋炒粿條 Baan Yai", "notes": "傳承50年的家族老店，以炭火大鍋現炒出的粿條香氣逼人。寬河粉配上鮮嫩蝦仁和滑蛋，鑊氣十足是泰式炒粿條的極致代表。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/f5010e87-e519-4ace-93f9-46a943feea63-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7405, "chef_name": null, "is_active": true, "longitude": 100.5149, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:58.439696+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《大屋炒粿條 Baan Yai》隱藏在 Thonglor 區的住宅巷弄裡,招牌小到容易錯過。這間家庭式餐館只賣粿條與幾道泰式小炒,但每道都是家常菜的最高水準。粿條分乾炒與湯麵兩種,乾炒的焦香來自大火快炒的鍋氣,湯麵的高湯熬了數小時,豬骨與香料的味道濃郁但不油膩。配菜是醃辣椒、豆芽與檸檬,自己調整味道。店內沒有裝潢,塑膠椅與鐵桌,電風扇呼呼作響。這是曼谷在地人才知道的私房美食,沒有英文菜單,沒有觀光客,只有最真實的泰國味道。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Baan Yai", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "ea6b8d4e-29b7-4c2e-ad4f-f0d1ef7e3cab", "fax": null, "name": "白淺灘文化村", "notes": "比甘川文化村更隱密的壁畫村，遊客較少。沿著廢棄鐵道建造，有火車造型裝置藝術。氛圍悠閒文青，適合慢慢散步拍照。附近有海邊咖啡廳。\n\n旅遊提示：人少好拍，適合不喜歡人擠人的遊客", "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "gyeongju", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 35.5833, "chef_name": null, "is_active": true, "longitude": 129.35, "meal_type": null, "region_id": null, "address_en": null, "country_id": "korea", "created_at": "2026-04-06T23:23:52.