ighlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "吉隆坡塔，高421公尺，吉隆坡第二高建築。觀景台高276公尺，可360度俯瞰吉隆坡市區、雙峰塔、吉隆坡森林保護區。SkyDeck玻璃地板可看腳下城市，SkyBox懸空觀景箱刺激。門票約105馬幣，建議傍晚上塔。塔內有旋轉餐廳。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "MY", "cuisine_type": null, "dining_style": null, "english_name": null, "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "f1e2df38-5f3b-4c38-beb7-931436eb7315", "fax": null, "name": "暹羅天地ICONSIAM", "notes": "曼谷最新最大購物中心。G樓有室內水上市場。河畔美食廣場很棒。免費接駁船從BTS沙潘塔克辛站。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/52d0aaeb-c015-4d19-858b-a861ab83bc2d-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.7264, "chef_name": null, "is_active": true, "longitude": 100.51, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:34.750672+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《暹羅天地 ICONSIAM》坐落昭披耶河畔，結合了國際精品與泰國工藝的當代空間。地下一樓的 SookSiam 集結全國各地市集風貌，從南部海鮮到北部織品，濃縮成室內街區。河景落地窗外是往返的渡輪，日落時分光影變化最為動人。這裡不只是消費場所，更像一座城市縮影——高樓層的米其林餐廳與地下層的小吃攤共存，各自精彩。夜晚的水幕燈光秀技術精湛，但真正吸引人的是那份對在地文化的整理與再現。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": null, "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "f291efda-6b6f-46a4-9046-6b439231190b", "fax": null, "name": "神田", "notes": null, "phone": null, "awards": ["米其林三星"], "images": null, "rating": null, "address": null, "city_id": "tokyo", "ratings": null, "website": null, "category": null, "currency": "JPY", "latitude": null, "chef_name": "神田裕行", "is_active": true, "longitude": null, "meal_type": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2025-11-0