reen_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "曼谷文華東方酒店的傳奇法式餐廳，俯瞰湄南河美景。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Le Normandie", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "f7492c4c-72c0-42ed-b66e-81bd3eaa332f", "fax": null, "name": "Kiew Kai Ka", "notes": "推薦香料炸雞翅、北泰咖哩。人均約300-500泰銖。建議預約。位於清邁。", "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/9f5c57fa-9fa6-4df6-9b5a-3c76724dc7ab-1.jpeg"], "rating": null, "address": null, "city_id": "bangkok", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 13.723, "chef_name": null, "is_active": true, "longitude": 100.5283, "meal_type": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2026-04-06T23:22:59.454957+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "《Kiew Kai Ka》這間雞飯店的名字在泰文裡意思是「排隊等雞飯」,名副其實,隨時都要排隊。招牌是海南雞飯,雞肉煮到剛好斷生,皮薄肉嫩,雞油飯粒粒分明,配上特製醬汁與清湯。但真正讓人驚豔的是那碗湯,雞骨熬製的高湯清澈見底,卻有深厚的鮮味,加幾片冬瓜,簡單到極致。店內裝潢是典型的泰式快餐店:塑膠椅、日光燈、電視播著泰劇。這是曼谷飲食文化的核心:不需要裝潢,不需要噱頭,只要味道對了,人們願意排隊等待。這是庶民美食的高標準範本。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "TH", "cuisine_type": null, "dining_style": null, "english_name": "Kiew Kai Ka", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "f802f430-3be3-4165-a664-c2c62bb255d7", "fax": null, "name": "The Deck Saigon", "notes": "位於第二郡，需搭渡船前往。日落時段最浪漫。人均約500,000-800,000越盾。", "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "ho-chi-minh", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": 10.7747, "chef_name": null, "is_active": true, "longitude": 106.7031, "meal_type": null, "region_id": null, "address_en": null, "country_id": "vietnam", "created_at": "2026-04-06T23:24:00.055963+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "dress_code": null, "facilities": null, "green_star": false, "highlights": null, "name_local": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "best_season": null, "description": "TheDeckSaigon，胡志明市西貢河畔餐廳，景觀無敵。越南菜與西式料理融合，雞尾酒好喝。傍晚看日落、晚上看夜景，氣氛一流。這是胡志明市必訪餐廳，也是約會與商務宴請首選。價格約300,000-600,000越南盾/人。建議提前預訂河景座位。傍晚前往最美。", "is_featured": false, "menu_images": null, "price_range": null, "specialties": null, "bib_gourmand": false, "chef_profile": null, "country_code": "VN", "cuisine_type": null, "dining_style": null, "english_name": "The Deck Saigon", "private_room": false, "review_count": 0, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_notes": null, "booking_phone": null, "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "description_en": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "michelin_plate": false, "michelin_stars": null, "min_group_size": null, "avg_price_lunch": null, "booking_contact": null, "commission_rate": null, "dietary_options": null, "google_maps_url": null, "recommended_for": null, "reservation_url": null, "avg_price_dinner": null, "group_menu_price": null, "signature_dishes": null, "group_menu_options": null, "dining_restrictions": null, "michelin_guide_year": null, "group_menu_available": false, "reservation_required": false, "private_room_capacity": null}, {"id": "f82d3ab1-1442-486e-80b0-5687b187db81", "fax": null, "name": "舊城區", "notes": "雅加達舊城區Kota Tua，保留荷蘭殖民時期建築。法塔希拉廣場是中心，有歷史博物館、咖啡館。可租腳踏車遊覽。是了解印尼殖民歷史的好地方。\n\n旅遊提示：週末有街頭表演和市集", "phone": null, "awards": null, "images": null, "rating": null, "address": null, "city_id": "jakarta", "ratings": null, "website": null, "category": "餐廳 / Restaurant", "currency": "TWD", "latitude": -6.1375, "chef_name": null, "is_active": true, "longitude": 106.8133, "